package cli

import (
	"encoding/json"
	"fmt"
	"log"
	"os"
	"sort"
	"strings"

	tdns "github.com/johanix/tdns/v2"
	"github.com/miekg/dns"
	"github.com/spf13/cobra"
)

// The "imr" subtree is replicated under each parent command that
// names a daemon hosting an in-process IMR (agent, auth, ...). The
// parent identifies which API client to use; the leaf commands are
// generated by the factory functions below so the logic lives in one
// place.

var agentImrCmd = &cobra.Command{
	Use:   "imr",
	Short: "IMR (Internal Recursive Resolver) cache commands",
}

var authImrCmd = &cobra.Command{
	Use:   "imr",
	Short: "IMR (Internal Recursive Resolver) cache commands",
}

func newImrQueryCmd(role string) *cobra.Command {
	return &cobra.Command{
		Use:   "query <qname> <qtype>",
		Short: "Query the IMR cache (cache-only, no external queries)",
		Args:  cobra.ExactArgs(2),
		Run: func(cmd *cobra.Command, args []string) {
			qname := dns.Fqdn(args[0])
			qtype := args[1]

			amr, err := SendImrMgmtCmd(role, &tdns.ImrMgmtPost{
				Command: "imr-query",
				Data: map[string]interface{}{
					"qname": qname,
					"qtype": qtype,
				},
			})
			if err != nil {
				log.Fatalf("Request failed: %v", err)
			}
			if amr.Error {
				fmt.Fprintf(os.Stderr, "Error: %s\n", amr.ErrorMsg)
				os.Exit(1)
			}

			fmt.Println(amr.Msg)
			if amr.Data != nil {
				data, ok := amr.Data.(map[string]interface{})
				if ok {
					if records, ok := data["records"].([]interface{}); ok {
						for _, rr := range records {
							fmt.Printf("  %s\n", rr)
						}
					}
					fmt.Printf("  TTL: %v  Expires in: %s  Rcode: %s  State: %s  Context: %s\n",
						data["ttl"], data["expires_in"], data["rcode"], data["state"], data["context"])
				} else {
					buf, err := json.MarshalIndent(amr.Data, "", "  ")
					if err != nil {
						fmt.Fprintf(os.Stderr, "failed to marshal response Data: %v\n", err)
					} else {
						fmt.Println(string(buf))
					}
				}
			}
		},
	}
}

